export const SpinnerSizes = ["sm", "md", "lg", "xl", "xxl"] as const;
export type SpinnerSize = (typeof SpinnerSizes)[number];

export const SpinnerThicknesses = ["sm", "md"] as const;
export type SpinnerThickness = (typeof SpinnerThicknesses)[number];

export const DEFAULT_SPINNER_SIZE: SpinnerSize = "md";
export const DEFAULT_SPINNER_THICKNESS: SpinnerThickness = "sm";

/**
 * Mapping from Spinner size to pixel dimensions
 */
export const SpinnerSizeMap: Record<SpinnerSize, number> = {
  sm: 12,
  md: 16,
  lg: 24,
  xl: 32,
  xxl: 40,
} as const;

/**
 * Stroke width mapping for thickness variants
 */
export const SpinnerThicknessMap: Record<SpinnerThickness, number> = {
  sm: 2,
  md: 4,
} as const;
