import { forwardRef } from "react";
import type { HTMLAttributes } from "react";
import * as styles from "./Spinner.css";
import type { SpinnerSize, SpinnerThickness } from "./Spinner.config";
import {
  DEFAULT_SPINNER_SIZE,
  DEFAULT_SPINNER_THICKNESS,
  SpinnerSizeMap,
  SpinnerThicknessMap,
} from "./Spinner.config";
import { clsx } from "clsx";
import { useTranslations } from "../hooks/useTranslations";
import translations from "./i18n.json";

interface SpinnerCustomProps {
  /**
   * The size of the spinner
   * @default 'md'
   */
  size?: SpinnerSize;

  /**
   * The stroke thickness of the spinner
   * @default 'sm'
   */
  thickness?: SpinnerThickness;

  /**
   * Accessible label for the spinner, announced by screen readers.
   * Should be localized for internationalization.
   */
  label?: string;
}

export interface SpinnerProps
  extends
    Omit<HTMLAttributes<HTMLSpanElement>, keyof SpinnerCustomProps>,
    SpinnerCustomProps {}

export const Spinner = forwardRef<HTMLSpanElement, SpinnerProps>(
  (
    {
      size = DEFAULT_SPINNER_SIZE,
      thickness = DEFAULT_SPINNER_THICKNESS,
      label,
      className,
      ...props
    },
    ref
  ) => {
    const t = useTranslations(translations);
    const ariaLabel = label ?? t.loading;

    // Use actual pixel dimensions for viewBox so stroke width renders at true size
    const viewBoxSize = SpinnerSizeMap[size];
    const CENTER = viewBoxSize / 2;
    const strokeWidth = SpinnerThicknessMap[thickness];
    const radius = CENTER - strokeWidth / 2;

    // Arc path: starts at top (cx, cy - r), draws 90° clockwise to (cx + r, cy)
    const arcPath = `M ${CENTER} ${CENTER - radius} A ${radius} ${radius} 0 0 1 ${CENTER + radius} ${CENTER}`;

    return (
      <span
        ref={ref}
        className={clsx(styles.spinner({ size }), className)}
        role="status"
        aria-label={ariaLabel}
        {...props}
      >
        <svg
          className={styles.spinnerSvg}
          viewBox={`0 0 ${viewBoxSize} ${viewBoxSize}`}
          aria-hidden="true"
          xmlns="http://www.w3.org/2000/svg"
        >
          <circle
            className={styles.spinnerCircle[thickness]}
            cx={CENTER}
            cy={CENTER}
            r={radius}
          />
          <path className={styles.spinnerArc[thickness]} d={arcPath} />
        </svg>
      </span>
    );
  }
);

Spinner.displayName = "Spinner";
